import type { Project, SortOption, GalleryFilters } from './types'

const DATA_PATH = `${import.meta.dir}/data/projects.json`

const loadProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  return file.json()
}

const saveProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2))
}

const sortProjects = (projects: Project[], sort: SortOption): Project[] => {
  const sorted = [...projects]
  switch (sort) {
    case 'date-desc':
      return sorted.sort((a, b) => new Date(b.dateAdded).getTime() - new Date(a.dateAdded).getTime())
    case 'date-asc':
      return sorted.sort((a, b) => new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime())
    case 'alpha-asc':
      return sorted.sort((a, b) => a.title.localeCompare(b.title))
    case 'alpha-desc':
      return sorted.sort((a, b) => b.title.localeCompare(a.title))
    default:
      return sorted
  }
}

const filterProjects = (projects: Project[], filters: GalleryFilters): Project[] => {
  let result = [...projects]

  if (filters.tag) {
    const tag = filters.tag.toLowerCase()
    result = result.filter(p => p.tags.some(t => t.toLowerCase() === tag))
  }

  if (filters.search) {
    const query = filters.search.toLowerCase()
    result = result.filter(p => p.title.toLowerCase().includes(query))
  }

  const sort = filters.sort ?? 'date-desc'
  result = sortProjects(result, sort)

  return result
}

const getAllTags = (projects: Project[]): string[] => {
  const tagSet = new Set<string>()
  for (const p of projects) {
    for (const t of p.tags) {
      tagSet.add(t)
    }
  }
  return [...tagSet].sort()
}

const getProjectById = (projects: Project[], id: string): Project | undefined =>
  projects.find(p => p.id === id)

export { loadProjects, saveProjects, filterProjects, getAllTags, getProjectById }

import { h, Fragment } from 'plaited'
import { createSSR } from 'plaited/server'
import type { Project, GalleryFilters } from './types'
import { styles, styleToString } from './styles'

const s = styleToString

const renderTag = (tag: string, activeTag?: string) => {
  const isActive = activeTag?.toLowerCase() === tag.toLowerCase()
  const style = isActive ? styles.tagActive : styles.tag
  const href = isActive ? '/' : `/?tag=${encodeURIComponent(tag)}`
  return h('a', { href, style: s(style) }, tag)
}

const renderCard = (project: Project) =>
  h('article', { style: s(styles.card) },
    h('a', { href: `/project/${project.id}`, style: 'text-decoration:none;color:inherit;display:block' },
      h('img', {
        src: project.thumbnail,
        alt: project.title,
        style: s(styles.cardImage),
        loading: 'lazy',
      }),
    ),
    h('div', { style: s(styles.cardBody) },
      h('h3', { style: s(styles.cardTitle) },
        h('a', { href: `/project/${project.id}`, style: 'text-decoration:none;color:inherit' }, project.title),
      ),
      h('p', { style: s(styles.cardDesc) }, project.description),
      h('div', { style: s(styles.cardTags) },
        ...project.tags.map(tag =>
          h('span', { style: s(styles.cardTag) }, tag),
        ),
      ),
      h('div', { style: s(styles.cardLinks) },
        h('a', { href: project.demoUrl, target: '_blank', rel: 'noopener', style: s(styles.cardLink) }, 'Live Demo'),
        h('a', { href: project.sourceUrl, target: '_blank', rel: 'noopener', style: s(styles.cardLink) }, 'Source Code'),
      ),
    ),
  )

const renderGalleryPage = (
  projects: Project[],
  allTags: string[],
  filters: GalleryFilters,
) => {
  const sortValue = filters.sort ?? 'date-desc'
  const searchValue = filters.search ?? ''

  return h('html', { lang: 'en' },
    h('head', {},
      h('meta', { charset: 'UTF-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
      h('title', {}, 'Portfolio Gallery'),
      h('style', {}, `
        *, *::before, *::after { box-sizing: border-box; }
        body { margin: 0; padding: 0; }
        a:hover { opacity: 0.85; }
        article:hover { transform: translateY(-3px); box-shadow: 0 4px 16px rgba(0,0,0,0.1) !important; }
        input:focus { border-color: #0f3460 !important; }
        @media (max-width: 640px) {
          .pg-grid { grid-template-columns: 1fr !important; padding: 1rem !important; }
          .pg-controls { padding: 1rem !important; }
          .pg-tagbar { padding: 0.75rem 1rem !important; }
        }
      `),
    ),
    h('body', { style: s(styles.page) },
      h('header', { style: s(styles.header) },
        h('h1', { style: s(styles.headerTitle) }, 'Portfolio Gallery'),
        h('p', { style: s(styles.headerSub) }, `${projects.length} project${projects.length !== 1 ? 's' : ''} shown`),
      ),
      h('div', { class: 'pg-controls', style: s(styles.controls) },
        h('form', { method: 'get', action: '/', style: 'display:contents' },
          filters.tag ? h('input', { type: 'hidden', name: 'tag', value: filters.tag }) : h(Fragment, {}),
          h('input', {
            type: 'search',
            name: 'search',
            placeholder: 'Search projects by title...',
            value: searchValue,
            style: s(styles.searchInput),
          }),
          h('select', { name: 'sort', style: s(styles.select), onchange: 'this.form.submit()' },
            h('option', { value: 'date-desc', ...(sortValue === 'date-desc' ? { selected: 'selected' } : {}) }, 'Newest First'),
            h('option', { value: 'date-asc', ...(sortValue === 'date-asc' ? { selected: 'selected' } : {}) }, 'Oldest First'),
            h('option', { value: 'alpha-asc', ...(sortValue === 'alpha-asc' ? { selected: 'selected' } : {}) }, 'A \u2192 Z'),
            h('option', { value: 'alpha-desc', ...(sortValue === 'alpha-desc' ? { selected: 'selected' } : {}) }, 'Z \u2192 A'),
          ),
          h('button', {
            type: 'submit',
            style: 'padding:0.6rem 1.25rem;border:none;border-radius:8px;background:#0f3460;color:#fff;font-size:0.9rem;font-weight:600;cursor:pointer',
          }, 'Search'),
        ),
      ),
      h('div', { class: 'pg-tagbar', style: s(styles.tagBar) },
        ...allTags.map(tag => renderTag(tag, filters.tag)),
      ),
      projects.length > 0
        ? h('div', { class: 'pg-grid', style: s(styles.grid) },
            ...projects.map(renderCard),
          )
        : h('div', { style: s(styles.emptyState) },
            h('p', {}, 'No projects found matching your criteria.'),
            h('a', { href: '/', style: `color:#0f3460;text-decoration:none;font-weight:600` }, 'Clear filters'),
          ),
    ),
  )
}

const renderDetailPage = (project: Project) =>
  h('html', { lang: 'en' },
    h('head', {},
      h('meta', { charset: 'UTF-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
      h('title', {}, `${project.title} — Portfolio`),
      h('style', {}, `
        *, *::before, *::after { box-sizing: border-box; }
        body { margin: 0; padding: 0; }
        a:hover { opacity: 0.85; }
        .lb-thumb:hover { opacity: 0.8; }
        .lb-nav:hover { background: rgba(255,255,255,0.15); border-radius: 50%; }
        @media (max-width: 640px) {
          .pg-detail { padding: 1rem !important; }
          .pg-carousel { grid-template-columns: 1fr !important; }
        }
      `),
      h('script', {}, `
        const LB = {
          images: ${JSON.stringify(project.images)},
          idx: 0,
          open(i) {
            this.idx = i;
            this.update();
            document.getElementById('lightbox').style.display = 'flex';
            document.body.style.overflow = 'hidden';
          },
          close() {
            document.getElementById('lightbox').style.display = 'none';
            document.body.style.overflow = '';
          },
          prev() { this.idx = (this.idx - 1 + this.images.length) % this.images.length; this.update(); },
          next() { this.idx = (this.idx + 1) % this.images.length; this.update(); },
          update() {
            document.getElementById('lb-img').src = this.images[this.idx];
            document.getElementById('lb-counter').textContent = (this.idx + 1) + ' / ' + this.images.length;
          }
        };
        document.addEventListener('keydown', e => {
          const lb = document.getElementById('lightbox');
          if (lb.style.display !== 'flex') return;
          if (e.key === 'Escape') LB.close();
          if (e.key === 'ArrowLeft') LB.prev();
          if (e.key === 'ArrowRight') LB.next();
        });
      `),
    ),
    h('body', { style: s(styles.page) },
      h('header', { style: s(styles.header) },
        h('h1', { style: s(styles.headerTitle) }, project.title),
      ),
      h('div', { class: 'pg-detail', style: s(styles.detailContainer) },
        h('a', { href: '/', style: s(styles.backLink) }, '\u2190 Back to Gallery'),
        h('h2', { style: s(styles.detailTitle) }, project.title),
        h('div', { style: s(styles.detailMeta) },
          ...project.tags.map(tag =>
            h('a', { href: `/?tag=${encodeURIComponent(tag)}`, style: s(styles.tagActive) }, tag),
          ),
          h('span', { style: s(styles.detailDate) },
            `Added ${new Date(project.dateAdded).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })}`,
          ),
        ),
        h('div', { style: s(styles.detailLinks) },
          h('a', {
            href: project.demoUrl,
            target: '_blank',
            rel: 'noopener',
            style: s({ ...styles.detailLinkBtn, ...styles.demoBtnStyle }),
          }, 'Live Demo'),
          h('a', {
            href: project.sourceUrl,
            target: '_blank',
            rel: 'noopener',
            style: s({ ...styles.detailLinkBtn, ...styles.sourceBtnStyle }),
          }, 'Source Code'),
        ),
        h('p', { style: s(styles.detailDesc) }, project.fullDescription),
        h('div', { class: 'pg-carousel', style: s(styles.carousel) },
          ...project.images.map((img, i) =>
            h('img', {
              src: img,
              alt: `${project.title} screenshot ${i + 1}`,
              class: 'lb-thumb',
              style: s(styles.carouselThumb),
              loading: 'lazy',
              onclick: `LB.open(${i})`,
            }),
          ),
        ),
      ),
      // Lightbox overlay
      h('div', { id: 'lightbox', style: s(styles.lightboxOverlay), onclick: 'LB.close()' },
        h('button', {
          style: s(styles.lightboxClose),
          onclick: 'event.stopPropagation();LB.close()',
          'aria-label': 'Close lightbox',
        }, '\u00d7'),
        h('button', {
          class: 'lb-nav',
          style: s({ ...styles.lightboxNav, left: '0.5rem' }),
          onclick: 'event.stopPropagation();LB.prev()',
          'aria-label': 'Previous image',
        }, '\u2039'),
        h('img', {
          id: 'lb-img',
          src: project.images[0] ?? '',
          alt: 'Lightbox image',
          style: s(styles.lightboxImage),
          onclick: 'event.stopPropagation()',
        }),
        h('button', {
          class: 'lb-nav',
          style: s({ ...styles.lightboxNav, right: '0.5rem' }),
          onclick: 'event.stopPropagation();LB.next()',
          'aria-label': 'Next image',
        }, '\u203a'),
        h('div', {
          id: 'lb-counter',
          style: 'position:absolute;bottom:1.5rem;color:#fff;font-size:0.9rem;opacity:0.8',
          onclick: 'event.stopPropagation()',
        }, `1 / ${project.images.length}`),
      ),
    ),
  )

const renderToHTML = (template: ReturnType<typeof h>): string => {
  const ssr = createSSR()
  return '<!DOCTYPE html>' + ssr(template)
}

export { renderGalleryPage, renderDetailPage, renderToHTML }

import type { GalleryFilters, SortOption } from './types'
import { loadProjects, filterProjects, getAllTags, getProjectById } from './store'
import { renderGalleryPage, renderDetailPage, renderToHTML } from './render'

const parseSortOption = (value: string | null): SortOption => {
  const valid: SortOption[] = ['date-desc', 'date-asc', 'alpha-asc', 'alpha-desc']
  return valid.includes(value as SortOption) ? (value as SortOption) : 'date-desc'
}

const htmlResponse = (html: string, status = 200) =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const handleGallery = async (url: URL): Promise<Response> => {
  const allProjects = await loadProjects()
  const allTags = getAllTags(allProjects)

  const filters: GalleryFilters = {
    tag: url.searchParams.get('tag') ?? undefined,
    search: url.searchParams.get('search') ?? undefined,
    sort: parseSortOption(url.searchParams.get('sort')),
  }

  const filtered = filterProjects(allProjects, filters)
  const page = renderGalleryPage(filtered, allTags, filters)
  return htmlResponse(renderToHTML(page))
}

const handleDetail = async (id: string): Promise<Response> => {
  const allProjects = await loadProjects()
  const project = getProjectById(allProjects, id)

  if (!project) {
    return htmlResponse('<h1>Project not found</h1><a href="/">Back to gallery</a>', 404)
  }

  const page = renderDetailPage(project)
  return htmlResponse(renderToHTML(page))
}

const handleApiProjects = async (url: URL): Promise<Response> => {
  const allProjects = await loadProjects()
  const filters: GalleryFilters = {
    tag: url.searchParams.get('tag') ?? undefined,
    search: url.searchParams.get('search') ?? undefined,
    sort: parseSortOption(url.searchParams.get('sort')),
  }
  return jsonResponse(filterProjects(allProjects, filters))
}

const handleApiProjectById = async (id: string): Promise<Response> => {
  const allProjects = await loadProjects()
  const project = getProjectById(allProjects, id)
  if (!project) return jsonResponse({ error: 'Project not found' }, 404)
  return jsonResponse(project)
}

export { handleGallery, handleDetail, handleApiProjects, handleApiProjectById }

import { handleGallery, handleDetail, handleApiProjects, handleApiProjectById } from './routes'

const PORT = Number(process.env.PORT) || 3000

const extractProjectId = (pathname: string, prefix: string): string | null => {
  if (!pathname.startsWith(prefix)) return null
  const id = pathname.slice(prefix.length)
  return id.length > 0 ? id : null
}

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url

    if (pathname === '/' && req.method === 'GET') {
      return handleGallery(url)
    }

    const projectId = extractProjectId(pathname, '/project/')
    if (projectId && req.method === 'GET') {
      return handleDetail(projectId)
    }

    if (pathname === '/api/projects' && req.method === 'GET') {
      return handleApiProjects(url)
    }

    const apiProjectId = extractProjectId(pathname, '/api/projects/')
    if (apiProjectId && req.method === 'GET') {
      return handleApiProjectById(apiProjectId)
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Portfolio Gallery running at http://localhost:${server.port}`)

export default server
